```json
{
  "global": "Navigate the product catalog to locate all power supply units with at least 600W output, then identify the one with the lowest price.",
  "subtasks": [
    {
      "subtask": "Open the hardware/product catalog in the web application",
      "atomics": [
        "Locate and click the catalog or product menu entry in the navigation sidebar",
        "Confirm the catalog page has loaded and displays product listings"
      ]
    },
    {
      "subtask": "Filter the catalog to show only power supply unit items",
      "atomics": [
        "Enter 'power supply' (or 'PSU') into the catalog search or filter field",
        "Apply the search and verify results are scoped to power supply units"
      ]
    },
    {
      "subtask": "Apply a minimum 600W power output constraint",
      "atomics": [
        "Locate a power/wattage filter control or column in the results",
        "Set the filter to show only items with power output >= 600W",
        "Confirm the result set excludes sub-600W units"
      ]
    },
    {
      "subtask": "Identify the cheapest qualifying unit",
      "atomics": [
        "Sort the filtered results by price in ascending order, or scan all visible prices",
        "Read the price of the top (lowest-price) item in the sorted list",
        "Record the product name and price of that item"
      ]
    }
  ],
  "global_atomics": [
    "Verify the identified item's wattage spec is explicitly >= 600W before reporting it as the answer"
  ],
  "gold_actions": {
    "global": "Use catalog search and filtering in the ServiceNow/WorkArena product catalog to return the name and price of the least-expensive PSU with power output >= 600W.",
    "subtasks": [
      {
        "subtask": "Navigate to the product catalog page",
        "atomics": [
          "Click 'Self-Service > Order Something' or equivalent catalog link in the left nav",
          "Assert page title or breadcrumb confirms the catalog view is active"
        ]
      },
      {
        "subtask": "Search for power supply units within the catalog",
        "atomics": [
          "Type 'power supply' into the catalog search box and press Enter",
          "Confirm returned rows all correspond to PSU product entries"
        ]
      },
      {
        "subtask": "Filter results to only units with >= 600W output",
        "atomics": [
          "Click the wattage/power filter or column header to expose filter input",
          "Enter '600' as the minimum wattage threshold and apply",
          "Verify displayed items show power specs of 600W or above"
        ]
      },
      {
        "subtask": "Find and extract the minimum-price item",
        "atomics": [
          "Click the 'Price' column header to sort ascending by cost",
          "Read the product name and unit price of the first row in the sorted list",
          "Note the exact price value (e.g., '$X.XX') and product SKU/name"
        ]
      }
    ],
    "global_atomics": [
      "Cross-check the selected product's detail page to confirm the listed wattage is >= 600W before submitting the answer"
    ]
  }
}
```
